#pragma once

#include "pybind11.hpp"
#include "signals/internal_signals_ax46mpv.hpp"
#include "utils/ahb.hpp"
#include "utils/axi.hpp"
#include "utils/cpu_signal_registry.hpp"
#include "utils/duplicator.hpp"
#include "utils/signals.hpp"
#include "verilated.h"

#include <axi/pin/axi4_initiator.h>
#include <axi/pin/axi4_target.h>
#include <systemc>
#include <Vax46mpv_advanced.h>
#include <Vax46mpv_advanced___024root.h>

#include <cstddef>

#include <array>

struct ax46mpv_cpu_cluster_subsystem
    : public Vax46mpv_advanced,
      public CpuSignalRegistry<ax46mpv_cpu_cluster_subsystem>
{
  using SC_CURRENT_USER_MODULE = ax46mpv_cpu_cluster_subsystem;

  ax46mpv_cpu_cluster_subsystem(const sc_core::sc_module_name& name = "ax46mpv")
      : Vax46mpv_advanced{name}
  {}

#define VERILOG_DEFINE(key, value) static constexpr auto key = value;
#include <Vax46mpv_advanced_config.h>

  // Limit maximum number of cores to 2 due to performance concerns
  static_assert(
    _NDS_NHART <= 2,
    "This subsystem only supports up to 2 cores. Please reconfigure with _NDS_NHART <= 2");

  static constexpr auto SYSTEM_BUS_TYPE = BusTypes::AXI;

  static constexpr auto dmi_addr_width = 9;
  static constexpr auto dmi_data_width = 32;
  static constexpr auto has_shared_cache = (NDS_L3C_CACHE_SIZE_KB > 0);

  using Vax46mpv_advanced::contextp;
  using Vax46mpv_advanced::final;
  using Vax46mpv_advanced::modelName;
  using Vax46mpv_advanced::threads;
  using Vax46mpv_advanced::trace;

  using bus_cfg =
    axi::axi4_cfg<NDS_BIU_DATA_WIDTH, NDS_BIU_ADDR_WIDTH, NDS_BIU_ID_WIDTH, 1>;

  using slv_cfg = axi::
    axi4_cfg<NDS_BIU_DATA_WIDTH, NDS_BIU_ADDR_WIDTH, NDS_BIU_ID_WIDTH + 4, 1>;

  axi_signals<bus_cfg> mem{"mem"};
  axi::pin::axi4_target<bus_cfg> mem_bfm{"mem_bfm"};

  axi_signals<bus_cfg> mmio{"mmio"};
  axi::pin::axi4_target<bus_cfg> mmio_bfm{"mmio_bfm"};

#if _NDS_NHART > 1
  // signal duplicators, used for multi-core
  BoolToUint<_NDS_NHART> mp_clk_dup{"mp_clk_dup"};
  sc_core::sc_signal<sc_dt::sc_uint<_NDS_NHART>> mp_core_clk;
#endif // _NDS_NHART

  UintToBool<_NDS_NHART> reset_narrow{"reset_narrow"};
  sc_core::sc_signal<bool> resetn_bool;

#ifdef _NDS_IO_HVM_SUBP
  axi_signals<slv_cfg> hvm{"hvm"};
  axi::pin::axi4_initiator<slv_cfg> hvm_bfm{"hvm_bfm"};
#endif // _NDS_IO_HVM_SUBP

  axi_signals<slv_cfg> slv{"slv"};
  axi::pin::axi4_initiator<slv_cfg> slv_bfm{"slv_bfm"};

#if _NDS_PC_GPR_PROBING_SUPPORT_INT == 1
  sc_core::sc_signal<vlpin<NDS_VALEN>> current_pc_hart0{"current_pc_hart0", 0};
  sc_core::sc_signal<vlpin<NDS_XLEN>> gpr_value_hart0{"gpr_value_hart0", 0};
  sc_core::sc_signal<vlpin<13>> gpr_index_hart0{"gpr_index_hart0", 0};

#if _NDS_NHART > 1
  sc_core::sc_signal<vlpin<NDS_VALEN>> current_pc_hart1{"current_pc_hart1", 0};
  sc_core::sc_signal<vlpin<NDS_XLEN>> gpr_value_hart1{"gpr_value_hart1", 0};
  sc_core::sc_signal<vlpin<13>> gpr_index_hart1{"gpr_index_hart1", 0};
#endif // _NDS_NHART

#endif // _NDS_PC_GPR_PROBING_SUPPORT_INT == 1

#if _NDS_NHART > 1
  sc_core::sc_signal<bool> wfi_signal_hart1;
#endif // _NDS_NHART

  auto bind(
    const sc_core::sc_clock& clk,
    const sc_core::sc_signal<sc_dt::sc_uint<_NDS_NHART>>& reset,
    std::array<sc_core::sc_signal<vlpin<NDS_VALEN>>, _NDS_NHART>& reset_vector,
    ahb::signals<dmi_addr_width, dmi_data_width>& dmi,
    sc_core::sc_signal<bool>& wfi_signal,
    sc_core::sc_signal<sc_dt::sc_uint<31>>& int_trigger)
  {
    // extract bit 0 from multi-bit reset for single-bit ports
    reset_narrow.sig_in.bind(reset);
    reset_narrow.sig_out.bind(resetn_bool);
    this->mem_bfm.clk_i.bind(clk);
    this->mmio_bfm.clk_i.bind(clk);

#ifdef _NDS_IO_HVM_SUBP
    this->hvm_bfm.clk_i.bind(clk);
#endif // _NDS_IO_HVM_SUBP

    this->slv_bfm.clk_i.bind(clk);

#define BIND_AXI(bfm, signals) \
  bfm.bind_ar(signals); \
  bfm.bind_r(signals); \
  bfm.bind_aw(signals); \
  bfm.bind_w(signals); \
  bfm.bind_b(signals);

    BIND_AXI(this->mem_bfm, this->mem);
    BIND_AXI(this->mmio_bfm, this->mmio);

#ifdef _NDS_IO_HVM_SUBP
    BIND_AXI(this->hvm_bfm, this->hvm);
#endif // _NDS_IO_HVM_SUBP

    BIND_AXI(this->slv_bfm, this->slv);

#ifdef _NDS_IO_HVM_SUBP
#define X(ch, name) this->hvm_sub_##ch##name.bind(this->hvm.ch##_##name);
    EXPAND_AXI4_SIGNALS
#undef X
#endif // _NDS_IO_HVM_SUBP

#define X(ch, name) \
  this->mem0_##ch##name.bind(this->mem.ch##_##name); \
  this->mmio0_##ch##name.bind(this->mmio.ch##_##name); \
  this->slv_##ch##name.bind(this->slv.ch##_##name);

    EXPAND_AXI4_SIGNALS

#undef X

#define X(name) this->dmi_##name.bind(dmi.name);
    EXPAND_AHB_SIGNALS_NO_HREADY
#undef X
    this->dmi_hreadyout.bind(dmi.hready);

    this->dmi_hsel.bind(signals::one);
    this->dmi_hready.bind(signals::one);

#if _NDS_NHART > 1
    mp_clk_dup.sig_in.bind(clk);
    mp_clk_dup.sig_out.bind(mp_core_clk);

    this->core_clk.bind(mp_core_clk);
    this->dc_clk.bind(mp_core_clk);
    this->lm_clk.bind(mp_core_clk);
    this->vpu_clk.bind(mp_core_clk);
    this->core_resetn.bind(reset);
    this->core_smem_resetn.bind(reset);
    this->slvp_resetn.bind(reset);
#else // _NDS_NHART == 1
    this->core_clk.bind(clk);
    this->dc_clk.bind(clk);
    this->lm_clk.bind(clk);
    this->vpu_clk.bind(clk);
    this->core_resetn.bind(resetn_bool);
    this->core_smem_resetn.bind(resetn_bool);
    this->slvp_resetn.bind(resetn_bool);
#endif // _NDS_NHART

    // this->l2_clk.bind(clk);
    this->aclk.bind(clk);
    this->mtime_clk.bind(clk);
    this->hvm_clk(clk);
    this->smem_clk(clk);

    this->smem_resetn.bind(resetn_bool);
    this->por_rstn.bind(resetn_bool);
    this->test_rstn.bind(resetn_bool);
    // this->l2_resetn.bind(resetn_bool);
    this->aresetn.bind(resetn_bool);
    this->dmi_resetn.bind(resetn_bool);
    // this->core_l2_resetn.bind(resetn_bool);
    this->hvm_reset_n(resetn_bool);

    this->hart0_reset_vector.bind(reset_vector[0]);
    signals::ignore(this->hart0_dcache_disable_init);
    signals::ignore(this->hart0_icache_disable_init);
    signals::ignore(this->hart0_nmi);
    signals::ignore(this->hart0_wakeup_event);

#if _NDS_NHART > 1
    this->hart1_reset_vector.bind(reset_vector[1]);
    signals::ignore(this->hart1_dcache_disable_init);
    signals::ignore(this->hart1_icache_disable_init);
    signals::ignore(this->hart1_nmi);
    signals::ignore(this->hart1_wakeup_event);
#endif // _NDS_NHART

    this->axi_bus_clk_en.bind(signals::one);
    this->test_mode(signals::zero);

    // IMPORTANT, to enable vpu clock gen, but why ?
    // In file : kv_vclk_gen.v , with scan_enable = 1, all VPU functional
    // units have a driven clock connected to vpu_clk. Everyting is same as
    // AX45MPV, so is correct.
    // But with scan_enable = 0, only vpermut_clk is driven few cycles `LATER`
    // after vpermut_reset, and the wrong timing causes
    // vpu_vpermut_standby_ready = 0, causing vpu_active = 1,
    // causing mstatus_fs_unready = 1, causing the cpu stall (ii_i0_stall = 1)
    // when an instruction tries to access CSR mstatus.
    this->scan_enable(signals::one);

    signals::ignore(this->dbg_srst_req);
    signals::ignore(this->dmactive);
    // signals::ignore(this->hart0_lm_local_int_event);
    // signals::ignore(this->l2c_err_int);
    signals::ignore(this->vpu_clk_en);
    signals::ignore(this->smem_async_error);
    this->int_src.bind(int_trigger);
    this->hart0_core_wfi_mode.bind(wfi_signal);

#if _NDS_NHART > 1
    this->hart1_core_wfi_mode.bind(wfi_signal_hart1);
#endif // _NDS_NHART

#if _NDS_PC_GPR_PROBING_SUPPORT_INT == 1
    this->hart0_probe_current_pc.bind(current_pc_hart0);
    this->hart0_probe_selected_gpr_value(gpr_value_hart0);
    this->hart0_probe_gpr_index.bind(gpr_index_hart0);

#if _NDS_NHART > 1
    this->hart1_probe_current_pc.bind(current_pc_hart1);
    this->hart1_probe_selected_gpr_value(gpr_value_hart1);
    this->hart1_probe_gpr_index.bind(gpr_index_hart1);
#endif // _NDS_NHART

#endif // _NDS_PC_GPR_PROBING_SUPPORT_INT == 1
  }

#if _NDS_PC_GPR_PROBING_SUPPORT_INT == 1
  uint64_t get_current_pc() { return current_pc_hart0.read(); }

  uint32_t get_gpr(uint16_t idx)
  {
    gpr_index_hart0.write(idx);
    return gpr_value_hart0.read();
  }
#endif // _NDS_PC_GPR_PROBING_SUPPORT_INT == 1

  // Returns all committed PCs from all cores and all issue slots
  // Result: vector[core_id] contains vector of committed PCs for that core
  // Each inner vector has 0-2 entries depending on how many instructions
  // committed (ax46mpv is 2-issue)
  std::vector<std::vector<uint64_t>> get_committed_pc()
  {
    std::vector<std::vector<uint64_t>> result(_NDS_NHART);

    // Core 0 - 2 issue slots
    if (this->rootp->WB_I0_RETIRE_C0) {
      result[0].push_back(this->rootp->WB_I0_PC_C0);
    }
    if (this->rootp->WB_I1_RETIRE_C0) {
      result[0].push_back(this->rootp->WB_I1_PC_C0);
    }

#if _NDS_NHART > 1
    // Core 1 - 2 issue slots
    if (this->rootp->WB_I0_RETIRE_C1) {
      result[1].push_back(this->rootp->WB_I0_PC_C1);
    }
    if (this->rootp->WB_I1_RETIRE_C1) {
      result[1].push_back(this->rootp->WB_I1_PC_C1);
    }
#endif

    return result;
  }

  // Returns last PC values from all issue slots (no retire check)
  // Result: vector[core_id] contains all PC values from that core's issue slots
  // Always returns 2 entries per core (may contain stale values if slot didn't
  // commit)
  std::vector<std::vector<uint64_t>> get_last_committed_pc()
  {
#if _NDS_NHART > 1
    return {{this->rootp->WB_I0_PC_C0, this->rootp->WB_I1_PC_C0},
            { this->rootp->WB_I0_PC_C1,
              this->rootp->WB_I1_PC_C1 }};
#else
    return {{this->rootp->WB_I0_PC_C0, this->rootp->WB_I1_PC_C0}};
#endif
  }

  static CpuSignalRegistry<ax46mpv_cpu_cluster_subsystem>::Registry
  build_signal_registry()
  {
    using Self = ax46mpv_cpu_cluster_subsystem;
    CpuSignalRegistry<Self>::Registry reg;

#if defined(EXPAND_INTERNAL_SIGNALS)
#define X(name, signal) \
  reg.emplace(#name, [](const Self& s) -> uint64_t { \
    return widen_to_u64(s.rootp->signal); \
  });
    EXPAND_INTERNAL_SIGNALS
    EXPAND_VPU_INTERNAL_SIGNALS
#undef X
#endif // EXPAND_INTERNAL_SIGNALS

#if defined(EXPAND_INTERNAL_MASKED_SIGNALS)
#define X(name, signal, shift, mask) \
  reg.emplace(#name, [](const Self& s) -> uint64_t { \
    return static_cast<uint64_t>((s.rootp->signal >> (shift)) & (mask)); \
  });
    EXPAND_INTERNAL_MASKED_SIGNALS
#undef X
#endif // EXPAND_INTERNAL_MASKED_SIGNALS

    // decode[37] = write to mask register
    // decode[48] = reduction, write to single vd
    // decode[51] = vd whole register
    reg.emplace("i0_write_whole_vd", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 5) & 0x1) | ((d[1] >> 16) & 0x1) | ((d[1] >> 19) & 0x1);
    });

    reg.emplace("i1_write_whole_vd", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 5) & 0x1) | ((d[1] >> 16) & 0x1) | ((d[1] >> 19) & 0x1);
    });

    // decode[45 +:3] = ({3{instr_vlsu_vd_wholereg}} ...
    reg.emplace("i0_whole_vd_num", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 13) & 0b111) + 1;
    });

    reg.emplace("i1_whole_vd_num", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 13) & 0b111) + 1;
    });

    // decode[21] = instr_vsetvli | instr_vsetivli | instr_vsetvl |
    // instr_vpermut_rd1_wen | instr_vmask_rd1_wen | instr_vace_rd1_wen |
    // instr_vlsu_rd1_wen ...
    reg.emplace("i0_rd1_wen", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[0] >> 21) & 0b1);
    });

    reg.emplace("i1_rd1_wen", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[0] >> 21) & 0b1);
    });

    // decode[53] = instr_valu_vd_x2 | instr_vmac_vd_x2 | instr_vfmis_vd_x2 |
    // instr_vace_vd_x2;
    reg.emplace("i0_vd_x2", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 21) & 0b1);
    });

    reg.emplace("i1_vd_x2", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 21) & 0b1);
    });

    // decode[54] = instr_vmac_vd_x4 | instr_vace_vd_x4;
    reg.emplace("i0_vd_x4", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i0_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 22) & 0b1);
    });

    reg.emplace("i1_vd_x4", [](const Self& s) -> uint64_t {
      auto& d =
        s.rootp
          ->ae350_vcpu_cluster_subsystem__DOT__u_cluster__DOT__u_complex0__DOT__gen_vpu__DOT__u_vpu__DOT__u_vdis__DOT__u_vdis_ctl__DOT__u_i1_dec__DOT__decode
          .m_storage;
      return ((d[1] >> 22) & 0b1);
    });

    return reg;
  }

#if ENABLE_PYBIND11
  static void bind_pybind11(pybind11::module_& m)
  {
    auto c = pybind11::class_<ax46mpv_cpu_cluster_subsystem>(
      m, "ax46mpv_cpu_cluster_subsystem");
    bind_registry_to_pybind11(c);
  }
#endif // ENABLE_PYBIND11
};

#ifndef MEMORY_MAP_H
#define MEMORY_MAP_H

/* RAM Bridge */
#define RAM_BASE 0x0
#define RAM_END 0x7FFFFFFF

/* Hart0 ILM SLAVEPORT */
#define HART0_ILM_BASE 0xA0000000
#define HART0_ILM_END 0xA01FFFFF

/* Hart0 DLM SLAVEPORT */
#define HART0_DLM_BASE 0xA0200000
#define HART0_DLM_END 0xA03FFFFF

/* Simulation control region */
#define SIM_CONTROL_BASE 0xE0080000
#define SIM_CONTROL_END 0xE0080FFF

/* Debug Module */
#define PLDM_BASE 0xE6800000
#define PLDM_END 0xE6800FFF

/* ACM (Andes Custom Memory) region */
#define ACM0_BASE 0xC0000000
#define ACM0_END 0xC0000FFF

/* AIA Machine-Level Interrupt File */
#define MLIF_BASE 0xC4000000
#define MLIF_END 0xC40FFFFF

/* AIA Supervisor-Level/Guest Interrupt File */
#define SLIF_BASE 0xC4100000
#define SLIF_END 0xC41FFFFF

/* SMU */
#define SMU_BASE 0xF0100000
#define SMU_END 0xF01FFFFF

/* UART1 */
#define UART1_BASE 0xF0200000
#define UART1_END 0xF02FFFFF

/* UART2 */
#define UART2_BASE 0xF0300000
#define UART2_END 0xF03FFFFF

/* AX66 Alias Region to RAM Bridge */
#define RAM_ALIAS_BASE 0x800000000
#define RAM_ALIAS_END 0x87FFFFFFF

#endif /* MEMORY_MAP_H */

