#pragma once

#include "memory_region.hpp"

#include <fmt/format.h>
#include <spdlog/spdlog.h>
#include <systemc>
#include <tlm>
#include <tlm_utils/multi_passthrough_initiator_socket.h>
#include <tlm_utils/multi_passthrough_target_socket.h>

#include <cstdint>

#include <map>
#include <set>

/**
 * An interconnect that routes transactions based on memory regions.
 * Uses plain TLM2.0 base protocol types — no AXI/AHB dependency.
 */
template<std::size_t BusWidth>
class Interconnect : public sc_core::sc_module
{
  using this_type = Interconnect<BusWidth>;
  using protocol_types = tlm::tlm_base_protocol_types;

  using base_initiator_socket =
    tlm::tlm_base_initiator_socket<BusWidth,
                                   tlm::tlm_fw_transport_if<protocol_types>,
                                   tlm::tlm_bw_transport_if<protocol_types>>;

  using base_target_socket =
    tlm::tlm_base_target_socket<BusWidth,
                                tlm::tlm_fw_transport_if<protocol_types>,
                                tlm::tlm_bw_transport_if<protocol_types>>;

  tlm_utils::
    multi_passthrough_initiator_socket<this_type, BusWidth, protocol_types>
      initiator_sockets{"initiator_sockets"};

  tlm_utils::
    multi_passthrough_target_socket<this_type, BusWidth, protocol_types>
      target_sockets{"target_sockets"};

  std::map<const tlm::tlm_generic_payload*, unsigned> trans_map;
  using fw_if = tlm::tlm_fw_transport_if<protocol_types>;
  std::vector<std::tuple<MemoryRegion, fw_if*, std::string>> memory_regions;
  std::vector<std::tuple<MemoryRegion, std::string>> reserved_regions;
  std::set<fw_if*> bound_targets;

  auto find_fw_if_from_address(const uint64_t addr) -> fw_if*
  {
    for (const auto& [mr, socket, _]: this->memory_regions) {
      if (mr.contains(addr))
        return socket;
    }

    return nullptr;
  }

